mapper.select:
select r.id, r.code, r.name, r.realm_type_id as realmTypeId, r.auth_policy_id as authPolicyId, r.register_enabled as registerEnabled, r.sso_enabled as ssoEnabled, r.sso_session_timeout as ssoSessionTimeout, r.sso_idle_timeout as ssoIdleTimeout, r.sso_single_logout as ssoSingleLogout, r.existing_session_handler as existingSessionHandler, r.no_client_id_handler as noClientIdHandler, r.password_policy as passwordPolicy, r.mfa_policy as mfaPolicy, r.unique_policy as uniquePolicy, ( select count(1) from app_client ac where ac.default_realm_id = r.id ) as ssoClientCount, ( select count(1) from account a where a.realm_id = r.id ) as accountCount, r.description, r.status, r.create_time, r.update_time from realm r
and r.`name` like concat('%', #{realmPageRequest.name}, '%')
and r.`code` = #{realmPageRequest.code}
and r.`status` = #{realmPageRequest.status}
and r.realm_type_id = #{realmPageRequest.realmTypeId}
order by r.update_time desc, r.create_time desc
